```ruby

// base.hpp

#include<vector>

template <typename M,
          typename G1>
struct  popb
{
  G1 g1;
  M m;
  popb(const G1 & _g1, const M & _m): g1(_g1), m(_m){}
};

template <typename M,
          typename G1,
          typename G2>
struct pop: public popb<M,G1>
{
  G2 g2;
  pop(const G1 & _g1, const M & _m, const G2 & _g2): popb<M,G1>(_g1,_m ),g2(_g2) {}
};

template <typename M,
          typename G1,
          typename G2,
          typename E>
struct newpop: pop<M,G1,G2>
{
  E e;
  newpop(const G1 & _g1, const M & _m, const G2 & _g2, const E & _e): pop<M,G1,G2>(_g1,_m,_g2), e(_e) {}
};

using newpop_t=newpop<std::vector<int>,std::vector<int>,std::vector<int>,int>;

newpop_t create_pop();



// base.cpp

#include "base.hpp"

newpop_t create_pop()
{
  std::vector<int> m = {7, 5, 16, 8};
  std::vector<int> g1 = {19, 3, 1, 8,5,3,2,1};
  std::vector<int> g2 = {2, 3, 8,30,2,1};
  int e=10;
  newpop_t pop(m,g1,g2,e);
  return pop;
}


// interface.cpp

<%
cfg['compiler_args'] = ['-std=c++11']
cfg['sources'] = ['base.cpp']
setup_pybind11(cfg)
%>

#include <pybind11/pybind11.h>
#include <pybind11/stl.h>
#include "base.hpp"

namespace py = pybind11;

using namespace pybind11::literals;

PYBIND11_PLUGIN(interface){
  py::module m("interface", "pybind11 interface");

  m.def("create_pop",&create_pop,"create pop");

  py::class_<newpop_t>(m,"newpop_t")
    .def_readwrite("g1",&newpop_t::g1)
    .def_readwrite("g2",&newpop_t::g2);

}


```

